@app.command("generate-api-test")
def generate_api_test(
    folder_name: str = typer.Argument(
        "generated_tests",
        help="Name of the folder to create under 'apps/' for generated tests.",
    ),
    schema_url: Optional[str] = typer.Option(
        None,
        "--schemaurl",
        help="URL pointing to the Swagger/OpenAPI schema.",
    ),
    schema_file: Optional[str] = typer.Option(
        None,
        "--schema",
        help="Path to a local Swagger/OpenAPI schema file.",
    ),
):
    """
    Run the API test generator.

    You must provide the API schema via exactly one of:
      --schemaurl   URL to a Swagger/OpenAPI schema
      --schema      Path to a local schema file
    """

    # --- Validate: exactly one of --schemaurl / --schema must be provided ---
    if schema_url and schema_file:
        logger.error("Provide either --schemaurl or --schema, not both.")
        raise typer.Exit(1)

    if not schema_url and not schema_file:
        logger.error(
            "Schema source is required.\n"
            "  Use --schemaurl <URL>   to download from a URL\n"
            "  Use --schema <path>     to use a local schema file"
        )
        raise typer.Exit(1)

    logger.info("Starting API Test Generator...")
    repo_root = os.getcwd()

    # Validation: output folder must be under apps/
    apps_dir = os.path.join(repo_root, "apps")
    target_output_dir = os.path.join(apps_dir, folder_name)

    # The api-test folder is in framework/api-test
    api_test_dir = os.path.join(repo_root, "framework", "api-test")
    script_path = os.path.join(api_test_dir, "run_test_generator.py")

    if not os.path.exists(script_path):
        logger.error(f"Test generator script not found at: {script_path}")
        sys.exit(1)

    # --- Download / copy schema into the api-test workspace ---
    if schema_url:
        try:
            resp = req.get(schema_url, timeout=15)
            resp.raise_for_status()
            # Determine filename from content type
            content_type = resp.headers.get("Content-Type", "")
            ext = ".json" if "json" in content_type else ".yaml"
            local_schema = os.path.join(api_test_dir, f"downloaded_schema{ext}")
            with open(local_schema, "w", encoding="utf-8") as f:
                f.write(resp.text)
            logger.info(f"Downloaded schema from: {schema_url}")
        except Exception as e:
            logger.error(f"Unable to download schema from provided URL: {e}")
            raise typer.Exit(1)
    else:
        if not os.path.isfile(schema_file):
            logger.error(f"Provided schema file does not exist: {schema_file}")
            raise typer.Exit(1)
        local_schema = os.path.join(api_test_dir, os.path.basename(schema_file))
        # Skip copy if src and dest resolve to the same path
        if os.path.abspath(schema_file) != os.path.abspath(local_schema):
            shutil.copy2(schema_file, local_schema)
            logger.info(f"Copied schema from: {schema_file}")
        else:
            logger.info("Schema file is already in workspace — skipping copy.")

    try:
        subprocess.check_call(
            [
                sys.executable,
                script_path,
                "--output",
                target_output_dir,
                "--schema-file",
                local_schema,
            ],
            cwd=api_test_dir,
        )
        logger.info(
            f"API Test Generator completed successfully. Output in: apps/{folder_name}"
        )
    except subprocess.CalledProcessError as e:
        logger.error(f"API Test Generator failed with exit code {e.returncode}")
        sys.exit(e.returncode)


@app.command("setup-claude")
def setup_claude(
    workspace: Optional[str] = typer.Option(
        None,
        "--workspace",
        "-w",
        help="Absolute path to the infobeans-qai project folder (default: current directory).",
    ),
    dry_run: bool = typer.Option(
        False,
        "--dry-run",
        help="Print the config that would be written without modifying anything.",
    ),
):
    """
    Register infobeans-qai as an MCP server in Claude Desktop.

    Writes (or merges) the infobeans-qai entry into:
      %APPDATA%\\Claude\\claude_desktop_config.json

    Run this once after setup, then fully restart Claude Desktop.
    The hammer (Tools) icon will appear in the Claude chat input.
    """
    import platform

    workspace_path = Path(workspace).resolve() if workspace else Path(os.getcwd()).resolve()
    python_exe = Path(sys.executable).resolve()

    # Locate the ibtest_mcp.py entry-point script.
    # Prefer the copy next to this file (project mode); fall back to site-packages.
    mcp_script = Path(__file__).with_name("ibtest_mcp.py").resolve()
    if not mcp_script.exists():
        # Installed package: find ibtest_mcp.py via the module's __file__
        try:
            import importlib.util
            spec = importlib.util.find_spec("ibtest_mcp")
            if spec and spec.origin:
                mcp_script = Path(spec.origin).resolve()
        except Exception:
            pass

    if not mcp_script.exists():
        typer.echo(
            f"ERROR: ibtest_mcp.py not found. Expected at {mcp_script}", err=True
        )
        raise typer.Exit(1)

    # Use forward slashes in paths written to JSON — Node.js (Claude Desktop)
    # handles them on Windows and they are never ambiguous, whereas backslash
    # paths can get double-escaped when round-tripped through certain shells,
    # resulting in paths like "Aarya\ Bhosale" (backslash-space) that break spawn.
    def _fwd(p: Path) -> str:
        return p.as_posix()

    # Sanity-check that the resolved paths actually exist before writing config.
    if not python_exe.exists():
        typer.echo(
            f"ERROR: Python executable not found at {python_exe}\n"
            "Make sure the virtual environment is activated before running setup-claude.",
            err=True,
        )
        raise typer.Exit(1)
    if not mcp_script.exists():
        typer.echo(f"ERROR: ibtest_mcp.py not found at {mcp_script}", err=True)
        raise typer.Exit(1)

    server_block = {
        "command": _fwd(python_exe),
        "args": [_fwd(mcp_script)],
        "env": {
            "INFOBEANS_QAI_WORKSPACE": _fwd(workspace_path),
        },
    }

    if dry_run:
        typer.echo("\nConfig block that would be written:")
        typer.echo(json.dumps({"mcpServers": {"infobeans-qai": server_block}}, indent=2))
        typer.echo(f"\nPython   : {_fwd(python_exe)}")
        typer.echo(f"Script   : {_fwd(mcp_script)}")
        typer.echo(f"Workspace: {_fwd(workspace_path)}")
        return

    # Warn if Claude Desktop is currently running — it will overwrite the config on quit.
    try:
        import psutil
        # Match only the main Claude Desktop executable, not helper/renderer processes.
        # On Windows it is typically "Claude.exe"; on macOS "Claude".
        claude_procs = [
            p for p in psutil.process_iter(["name"])
            if p.info["name"].lower() in ("claude.exe", "claude")
        ]
        if claude_procs:
            typer.echo(
                "\n  WARNING: Claude Desktop is running and will overwrite the config when it exits.\n"
                "  Please close it fully before continuing:\n"
                "    • If you see a Claude icon in the system tray: right-click → Quit\n"
                "    • If there is no tray icon: open Task Manager, find 'Claude.exe', End Task\n"
                "  Then re-run:  infobeans-qai setup-claude\n"
                "  And relaunch Claude Desktop afterwards.\n",
                err=True,
            )
            raise typer.Exit(1)
    except ImportError:
        pass  # psutil not available — skip the check, proceed anyway

    # Locate config file
    if platform.system() == "Windows":
        appdata = os.environ.get("APPDATA", "")
        config_dir = Path(appdata) / "Claude"
    elif platform.system() == "Darwin":
        config_dir = Path.home() / "Library" / "Application Support" / "Claude"
    else:
        config_dir = Path.home() / ".config" / "Claude"

    config_file = config_dir / "claude_desktop_config.json"
    config_dir.mkdir(parents=True, exist_ok=True)

    # Read existing config (if any) and merge
    existing = {}
    if config_file.exists():
        try:
            with open(config_file, "r", encoding="utf-8") as f:
                existing = json.load(f)
        except Exception:
            typer.echo(
                f"WARNING: Could not parse existing {config_file}. It will be overwritten.",
                err=True,
            )

    existing.setdefault("mcpServers", {})
    existing["mcpServers"]["infobeans-qai"] = server_block

    with open(config_file, "w", encoding="utf-8") as f:
        json.dump(existing, f, indent=2)

    typer.echo(f"\n  infobeans-qai MCP server registered in Claude Desktop.")
    typer.echo(f"  Config  : {config_file}")
    typer.echo(f"  Python  : {python_exe}")
    typer.echo(f"  Script  : {mcp_script}")
    typer.echo(f"  Workspace: {workspace_path}")
    typer.echo("")
    typer.echo("  Next steps:")
    typer.echo("    1. Fully quit Claude Desktop (right-click tray icon -> Quit).")
    typer.echo("    2. Reopen Claude Desktop.")
    typer.echo("    3. Look for the hammer (Tools) icon in the chat input.")
    typer.echo("")


@app.command("run-tests")
def run_tests(
    folder_name: str = typer.Argument(
        ...,
        help="Name of the folder inside 'apps/' containing test cases.",
    ),
):
    """
    Run pytest for a specific application folder inside apps/.

    Example:
      python ibtest.py run-tests my-tests
    """
    repo_root = os.getcwd()
    apps_dir = os.path.join(repo_root, "apps")
    target_dir = os.path.join(apps_dir, folder_name)

    # --- Validation ---
    if not os.path.isdir(target_dir):
        logger.error(
            f"Specified folder does not exist inside apps directory: apps/{folder_name}"
        )
        raise typer.Exit(1)

    # Check for pytest-compatible test files
    test_files = glob.glob(os.path.join(target_dir, "test_*.py")) + glob.glob(
        os.path.join(target_dir, "*_test.py")
    )
    if not test_files:
        logger.error(f"No pytest test cases found in: apps/{folder_name}")
        raise typer.Exit(1)

    logger.info(
        f"Running pytest for apps/{folder_name} ({len(test_files)} test file(s) found)"
    )

    try:
        result = subprocess.run(
            [sys.executable, "-m", "pytest", "-s", target_dir], cwd=repo_root
        )
        sys.exit(result.returncode)
    except Exception as e:
        logger.error(f"Failed to run pytest: {e}")
        raise typer.Exit(1)


if __name__ == "__main__":
    app()
